// serverPromptCapBytes caps the size of inline prompt bodies accepted on
// server-side ingress (POST /api/agent/run). FEAT-022 ┬¦9 / Stage D2. It is
// a package-level variable rather than a literal so tests can lower the
// cap without writing multi-MB request bodies. Production callers must not
// mutate it.
var serverPromptCapBytes = evidence.DefaultMaxPromptBytes

// serverBuildSHA returns the build's VCS revision for inclusion on
// operator-prompt audit events. Falls back to "unknown" when build info is
// unavailable (e.g. `go test` without -buildvcs or development builds).
func serverBuildSHA() string {
	info, ok := debug.ReadBuildInfo()
	if !ok {
		return "unknown"
	}
	for _, s := range info.Settings {
		if s.Key == "vcs.revision" && s.Value != "" {
			return s.Value
		}
	}
	return "unknown"
}

// serverInlineCapBytes caps inline content bodies returned on egress paths
// ŌĆö MCP tool responses and REST JSON responses that carry library-doc,
// execution-bundle, diff, session, or persona text. FEAT-022 ┬¦10 / ┬¦11.
// Stage E1. Package-level variable so tests can lower the cap; production
// callers must not mutate it.
var serverInlineCapBytes = evidence.DefaultMaxInlinedFileBytes

// mcpText constructs a text-typed mcpContent whose Text body is bounded by
// serverInlineCapBytes via evidence.ClampOutput. The Truncated and
// OriginalBytes fields are always populated (false/len(text) when the body
// fits within the cap). This is the single mcpContent{Type:"text"} literal
// site in this package ŌĆö every other caller must route through this helper
// so static analysis (TestEvidencePrimitiveUsage) can guarantee no
// unbounded text egress on the MCP surface. FEAT-022 ┬¦10 / Stage E1.
func mcpText(text string) mcpContent {
	clamped, truncated, originalBytes := evidence.ClampOutput(text, serverInlineCapBytes)
	// evidence:allow-unbounded reason="single mcpContent{Type:\"text\"} literal site for the package; Text is sourced from evidence.ClampOutput above (FEAT-022 ┬¦10 Stage E1)"
	return mcpContent{Type: "text", Text: clamped, Truncated: truncated, OriginalBytes: originalBytes}
}

// beadHubCloser is the minimal interface the Server requires from its bead
// lifecycle hub. *bead.WatcherHub satisfies this interface.
type beadHubCloser interface {
	SubscribeLifecycle(projectID string) (<-chan bead.LifecycleEvent, func())
	Close()
}

// Server is the DDx HTTP server exposing REST and MCP endpoints.
type Server struct {
	Addr        string
	WorkingDir  string
	TsnetConfig *config.TsnetConfig
	mux         *http.ServeMux
	startTime   time.Time
	workers     *WorkerManager
	beadHub     beadHubCloser
	state       *ServerState

	// csrfTokens issues and validates CSRF tokens for write mutations on
	// the GraphQL endpoint (Story 15 / operator-prompts). The token is
	// generated once at server construction and exposed to clients via
	// GET /api/csrf-token (localhost-gated).
	csrfTokens *ddxgraphql.StaticCSRFTokenStore
	// operatorPromptIdempotency deduplicates operatorPromptSubmit calls by
	// idempotency key within a 24-hour window. Process-local; survives
	// only for the lifetime of the server process.
	operatorPromptIdempotency *ddxgraphql.MemoryIdempotencyCache
	// operatorPromptAutoApproveAllowlist is the per-project allowlist of
	// localhost identity actors permitted to auto-approve their own
	// operator-prompt submissions and to invoke operatorPromptApprove. The
	// locked Story 15 decision restricts approval to configured-localhost
	// identities; ts-net peers are never eligible. Seeded from
	// DDX_OPERATOR_PROMPT_ALLOWLIST (comma-separated) at server construction
	// and may be overridden by tests via SetOperatorPromptAutoApproveAllowlist.
	operatorPromptAutoApproveAllowlist []string

	routePatterns []string // every pattern registered via route(); used by gate tests

	// HubMode is true once EnableHubMode has been called; the federation
	// HTTP routes are mounted only in that case (B14.3 AC: "Routes mounted
	// only when --hub-mode").
	HubMode bool
	hub     *federationHub

	// SpokeMode is true once EnableSpokeMode has been called. Used together
	// with HubMode to compute node.federation_role:
	//   neither   ŌåÆ "standalone"
	//   hub only  ŌåÆ "hub"
	//   spoke onlyŌåÆ "spoke"
	//   both      ŌåÆ "hub_spoke"
	SpokeMode bool
	spoke     *federationSpoke

	// gqlHandler is the singleton gqlgen HTTP handler. LAYER 2 of the
	// GraphQL multi-project fix (ddx-055e8d32) builds this once at first
	// request and reuses it across both /graphql and the scoped
	// /api/projects/{project}/graphql route ŌĆö per-request reconstruction
	// (LAYER 1) is no longer needed because the resolver reads WorkingDir
	// from the request context.
	gqlOnce    sync.Once
	gqlHandler http.Handler

	// workerIngest is the in-memory derived view of worker reports per
	// ADR-022 rev 5 ┬¦Worker-server interface. Workers POST register/event/
	// backfill best-effort; the registry is non-authoritative.
	workerIngest *workerIngestRegistry

	// reportedWorkers adapts workerIngest into the GraphQL reportedWorkers
	// resolver. Held on the Server (rather than constructed lazily) so the
	// ADR-022 step 5c integration test can swap the freshness clock and so
	// every /graphql request shares one instance.
	reportedWorkers *reportedWorkersAdapter
}

// New creates a new DDx server bound to addr, serving data from workingDir.
func New(addr, workingDir string) *Server {
	nodeName := resolveNodeName()
	stateDir := serverAddrDir() // XDG-standard user-level dir, one per node
	state := loadServerState(stateDir, nodeName)
	state.workingDir = workingDir

	workers := NewWorkerManager(workingDir)
	workers.ReconcileStaleWorkers()
	beadHub := bead.NewWatcherHub(250 * time.Millisecond)
	csrfStore, err := ddxgraphql.NewStaticCSRFTokenStore()
	if err != nil {
		// CSRF token generation should never fail outside of a broken
		// crypto/rand. Fall back to a deterministic stub that rejects
		// every request rather than failing open.
		csrfStore = ddxgraphql.NewStaticCSRFTokenStoreWithToken("")
	}
	s := &Server{
		Addr:                               addr,
		WorkingDir:                         workingDir,
		mux:                                http.NewServeMux(),
		startTime:                          time.Now().UTC(),
		workers:                            workers,
		beadHub:                            beadHub,
		state:                              state,
		csrfTokens:                         csrfStore,
		operatorPromptIdempotency:          ddxgraphql.NewMemoryIdempotencyCache(),
		operatorPromptAutoApproveAllowlist: parseOperatorPromptAllowlistEnv(os.Getenv("DDX_OPERATOR_PROMPT_ALLOWLIST")),
		workerIngest:                       newWorkerIngestRegistry(workingDir),
	}
	s.reportedWorkers = newReportedWorkersAdapter(s.workerIngest)
	state.coordinatorReg = workers.LandCoordinators

	// Register the server's own project immediately.
	state.RegisterProject(workingDir)
	_ = state.save()

	s.routes()
	return s
}

// parseOperatorPromptAllowlistEnv parses a comma-separated identity list
// (DDX_OPERATOR_PROMPT_ALLOWLIST) into a normalized allowlist. Empty entries
// are skipped; whitespace is trimmed. The literal sentinel "localhost"
// matches any localhost-kind actor.
func parseOperatorPromptAllowlistEnv(raw string) []string {
	if raw = strings.TrimSpace(raw); raw == "" {
		return nil
	}
	parts := strings.Split(raw, ",")
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		out = append(out, p)
	}
	return out
}

// SetOperatorPromptAutoApproveAllowlist replaces the in-memory allowlist
// used by operatorPromptSubmit (with autoApprove=true) and operatorPromptApprove.
// Tests use this to install a deterministic allowlist without juggling env vars.
func (s *Server) SetOperatorPromptAutoApproveAllowlist(allowlist []string) {
	s.operatorPromptAutoApproveAllowlist = append([]string(nil), allowlist...)
}

// resolveNodeName returns DDX_NODE_NAME env, or the system hostname.
func resolveNodeName() string {
	if n := os.Getenv("DDX_NODE_NAME"); n != "" {
		return n
	}
	if h, err := os.Hostname(); err == nil && h != "" {
		return h
	}
	return "unknown"
}

// Handler returns the server's HTTP handler (useful for testing).
func (s *Server) Handler() http.Handler {
	return s.mux
}

// State exposes the server's persistent state so adjacent packages (notably
// the perf harness) can register additional projects or query snapshots
// without reaching into unexported internals. The returned value MUST NOT be
// mutated concurrently with the server ŌĆö it is the same pointer the server
// itself uses.
func (s *Server) State() *ServerState {
	return s.state
}

package federation

import (
	"bytes"
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

// DefaultFanOutMaxConcurrency caps the number of in-flight per-spoke requests.
const DefaultFanOutMaxConcurrency = 8

// DefaultFanOutPerNodeTimeout is the default per-node deadline for one fan-out call.
const DefaultFanOutPerNodeTimeout = 5 * time.Second

// SkipReason is a short, machine-readable code describing why a spoke was
// skipped before any HTTP call was issued.
type SkipReason string

const (
	// SkipReasonIncompatibleVersion indicates the version handshake against the
	// hub's own version+schema rejected this spoke (e.g. major mismatch,
	// schema mismatch, unparseable ddx_version, ŌĆ”). The Handshake reason is
	// included in the logged message.
	SkipReasonIncompatibleVersion SkipReason = "incompatible_version"
	// SkipReasonMissingCapability indicates the spoke does not advertise one of
	// the capabilities required for this query.
	SkipReasonMissingCapability SkipReason = "missing_capability"
	// SkipReasonInvalidURL indicates the spoke's persisted URL did not parse.
	SkipReasonInvalidURL SkipReason = "invalid_url"
)

// NodeOutcomeKind describes how a single spoke contributed (or did not
// contribute) to a fan-out call. The hub uses this to update per-spoke status
// distinctly: offline (immediate transport failure on this fan-out) vs stale
// (heartbeat-overdue badge from the registry) vs ok.
type NodeOutcomeKind string

const (
	// OutcomeOK means the spoke returned a response (any HTTP 2xx).
	OutcomeOK NodeOutcomeKind = "ok"
	// OutcomeOffline means the transport itself failed: connection refused,
	// DNS error, TLS handshake failed, mid-response disconnect, etc. The hub
	// flips the spoke's registry status to StatusOffline on this outcome.
	OutcomeOffline NodeOutcomeKind = "offline"
	// OutcomeTimeout means the per-node timeout fired before a response was
	// fully received. Distinct from offline so callers can keep the spoke's
	// last-known status (likely stale) rather than promote it to offline.
	OutcomeTimeout NodeOutcomeKind = "timeout"
	// OutcomeHTTPError means the spoke responded with a non-2xx status. The
	// transport worked, so we do not flip to offline; the body is captured.
	OutcomeHTTPError NodeOutcomeKind = "http_error"
	// OutcomeSkipped means the spoke was filtered out before fan-out; see
	// NodeResult.SkipReason.
	OutcomeSkipped NodeOutcomeKind = "skipped"
)

// FanOutRequest is the GraphQL payload to send to every active spoke.
type FanOutRequest struct {
	Query         string         `json:"query"`
	OperationName string         `json:"operationName,omitempty"`
	Variables     map[string]any `json:"variables,omitempty"`
	// RequiredCapabilities, if non-empty, filters out spokes that do not
	// advertise every named capability in their SpokeRecord.Capabilities.
	RequiredCapabilities []string `json:"-"`
}

// NodeResult is a single spoke's contribution to a fan-out call.
type NodeResult struct {
	NodeID string
	URL    string
	// Status, when non-empty, is the registry status the hub should record for
	// this spoke as a result of this fan-out (StatusOffline on transport
	// failure). Empty means "do not change registry status".
	Status SpokeStatus
	// Outcome classifies how this spoke contributed.
	Outcome NodeOutcomeKind
	// Response is the raw GraphQL response body for OutcomeOK. The hub merges
	// it into the federated response shape. Empty otherwise.
	Response json.RawMessage
	// HTTPStatus is the HTTP status code seen, or 0 on transport failure.
	HTTPStatus int
	// Err is the underlying error for non-OK outcomes.
	Err error
	// SkipReason is set when Outcome == OutcomeSkipped.
	SkipReason SkipReason
	// SkipDetail is a free-form human message accompanying SkipReason.
	SkipDetail string
	// Duration is the wall time spent on this spoke's call.
	Duration time.Duration
}

// FanOutResult is the merged outcome of a fan-out call.
type FanOutResult struct {
	// Responses holds one entry per spoke that returned 2xx, keyed by node_id.
	// The value is the raw GraphQL response body.
	Responses map[string]json.RawMessage
	// Errors holds one entry per spoke that produced any non-OK outcome
	// (offline, timeout, http_error). Skipped spokes are NOT in this map ŌĆö
	// they appear in Skipped instead. Keyed by node_id.
	Errors map[string]error
	// Skipped holds one entry per spoke filtered out before fan-out, keyed by
	// node_id, with the SkipReason as the value.
	Skipped map[string]SkipReason
	// StatusUpdates lists the (node_id ŌåÆ new status) changes the hub should
	// apply to its registry as a side effect of this fan-out. Currently only
	// transport-level failures (StatusOffline) are emitted here; heartbeat-
	// driven status (stale) is left to the registry's own time-based reconcile.
	StatusUpdates map[string]SpokeStatus
	// Nodes is the per-node detail (every spoke considered, including skipped).
	// Order matches the input registry order for deterministic test output.
	Nodes []NodeResult
}

// FanOutClient executes fan-out GraphQL queries across a federation registry.
type FanOutClient struct {
	// HTTPClient is used for spoke /graphql calls. Nil ŌåÆ a default client that
	// accepts self-signed TLS certs (matches the spoke server's auto-cert).
	HTTPClient *http.Client
	// MaxConcurrency caps concurrent in-flight requests. Ōēż0 ŌåÆ default.
	MaxConcurrency int
	// PerNodeTimeout is the per-spoke deadline. Ōēż0 ŌåÆ default.
	PerNodeTimeout time.Duration
	// HubDDxVersion / HubSchemaVersion drive the version handshake gate.
	// Empty ŌåÆ version filter is skipped (test convenience).
	HubDDxVersion    string
	HubSchemaVersion string
	// Logger receives info/warn lines; nil ŌåÆ log.Printf.
	Logger func(format string, args ...any)
	// Now is the time source used for Duration measurement. Nil ŌåÆ time.Now.
	Now func() time.Time
}

// NewFanOutClient builds a FanOutClient with defaults filled in.
func NewFanOutClient() *FanOutClient {
	return &FanOutClient{
		HTTPClient: &http.Client{
			// Per-request deadlines drive cancellation; this is just a safety
			// net for misbehaving servers that never close the connection.
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		},
		MaxConcurrency: DefaultFanOutMaxConcurrency,
		PerNodeTimeout: DefaultFanOutPerNodeTimeout,
	}
}

func (c *FanOutClient) logf(format string, args ...any) {
	if c.Logger != nil {
		c.Logger(format, args...)
		return
	}
	log.Printf(format, args...)
}

func (c *FanOutClient) now() time.Time {
	if c.Now != nil {
		return c.Now()
	}
	return time.Now()
}

func (c *FanOutClient) maxConcurrency() int {
	if c.MaxConcurrency <= 0 {
		return DefaultFanOutMaxConcurrency
	}
	return c.MaxConcurrency
}

func (c *FanOutClient) perNodeTimeout() time.Duration {
	if c.PerNodeTimeout <= 0 {
		return DefaultFanOutPerNodeTimeout
	}
	return c.PerNodeTimeout
}

func (c *FanOutClient) httpClient() *http.Client {
	if c.HTTPClient != nil {
		return c.HTTPClient
	}
	return http.DefaultClient
}

// Execute fans out req across spokes. Returns a merged FanOutResult; never
// returns a non-nil error for per-spoke failures ŌĆö those are surfaced through
// FanOutResult.Errors. A non-nil error is reserved for misuse (e.g. nil req).
//
// The set of spokes considered is the input slice. Callers typically pass the
// hub registry's spokes filtered by Status == active|stale (offline/degraded
// handling depends on policy and is left to the caller). Skipped spokes still
// appear in the per-node Nodes detail with OutcomeSkipped + SkipReason.
//
// Cancellation: if ctx is canceled, in-flight goroutines abort their HTTP
// calls and return OutcomeOffline (with ctx.Err() as cause); callers that want
// to distinguish caller-cancellation from spoke failure should check ctx.Err()
// after Execute returns.
func (c *FanOutClient) Execute(ctx context.Context, spokes []SpokeRecord, req *FanOutRequest) (*FanOutResult, error) {
	if req == nil {
		return nil, errors.New("federation: fanout request is nil")
	}
	if strings.TrimSpace(req.Query) == "" {
		return nil, errors.New("federation: fanout request query is empty")
	}

	body, err := json.Marshal(struct {
		Query         string         `json:"query"`
		OperationName string         `json:"operationName,omitempty"`
		Variables     map[string]any `json:"variables,omitempty"`
	}{req.Query, req.OperationName, req.Variables})
	if err != nil {
		return nil, fmt.Errorf("federation: marshal fanout query: %w", err)
	}

	results := make([]NodeResult, len(spokes))
	sem := make(chan struct{}, c.maxConcurrency())
	var wg sync.WaitGroup

	for i := range spokes {
		i := i
		s := spokes[i]
		// Pre-flight filters: version, capability, URL.
		if skip, reason, detail := c.preflightSkip(s, req.RequiredCapabilities); skip {
			c.logf("federation fanout: skip node_id=%q reason=%s detail=%q", s.NodeID, reason, detail)
			results[i] = NodeResult{
				NodeID:     s.NodeID,
				URL:        s.URL,
				Outcome:    OutcomeSkipped,
				SkipReason: reason,
				SkipDetail: detail,
			}
			continue
		}

		wg.Add(1)
		go func() {
			defer wg.Done()
			select {
			case sem <- struct{}{}:
			case <-ctx.Done():
				results[i] = NodeResult{
					NodeID:  s.NodeID,
					URL:     s.URL,
					Outcome: OutcomeOffline,
					Status:  StatusOffline,
					Err:     ctx.Err(),
				}
				return
			}
			defer func() { <-sem }()

package server

import (
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// HubDefaultDDxVersion is the ddx_version the hub advertises when validating
// spoke handshakes. It is exposed as a field so tests and operators can pin
// the hub's view of "current ddx version" without rebuilding the binary.
const HubDefaultDDxVersion = "0.1.0"

// federationHub holds the per-server state for hub-mode federation: the
// in-memory registry, the disk path used to persist it, the warning logger
// (for plain-HTTP accepted registrations), and configuration knobs.
type federationHub struct {
	mu             sync.Mutex
	registry       *federation.FederationRegistry
	statePath      string // empty disables disk persistence
	allowPlainHTTP bool
	hubDDxVersion  string
	hubSchemaVer   string
	warnLog        func(format string, args ...any)
	warnings       []string // captured plain-HTTP warnings (test introspection)
	conflictsLog   []string // captured 409 conflict log lines (test introspection)
	now            func() time.Time
}

// EnableHubMode mounts the /api/federation/* routes on this server, switches
// the hub-mode flag on, and (best effort) loads the registry from disk so a
// hub restart can rebuild state from a prior session.
//
// Must be called before ListenAndServe / ListenAndServeTLS. Calling it more
// than once is a no-op after the first call.
//
// allowPlainHTTP relaxes the default ts-net/loopback peer policy on the
// federation routes ŌĆö non-trusted peers are accepted, but each accepted
// registration emits a WARN log entry. This is the operator opt-out for
// federations spanning networks where ts-net is not viable.
func (s *Server) EnableHubMode(allowPlainHTTP bool) {
	if s.hub != nil {
		return
	}
	statePath, err := federation.DefaultStatePath()
	if err != nil {
		statePath = ""
	}
	var reg *federation.FederationRegistry
	if statePath != "" {
		if loaded, lerr := federation.LoadStateFrom(statePath); lerr == nil {
			reg = loaded
		}
	}
	if reg == nil {
		reg = federation.NewRegistry()
	}
	s.hub = &federationHub{
		registry:       reg,
		statePath:      statePath,
		allowPlainHTTP: allowPlainHTTP,
		hubDDxVersion:  HubDefaultDDxVersion,
		hubSchemaVer:   federation.CurrentSchemaVersion,
		warnLog:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
		now:            time.Now,
	}
	s.HubMode = true

	gate := func(h http.HandlerFunc) http.HandlerFunc { return s.requireFederationTrusted(h) }
	s.route("POST /api/federation/register", gate(s.handleFederationRegister))
	s.route("POST /api/federation/heartbeat", gate(s.handleFederationHeartbeat))
	s.route("GET /api/federation/spokes", gate(s.handleFederationListSpokes))
	s.route("DELETE /api/federation/spokes/{id}", gate(s.handleFederationDeregister))
	s.route("POST /api/federation/projects/{project}/graphql", gate(s.handleFederationForwardMutation))
}

// HubFederationRegistrySnapshot returns a copy of the current registry, for
// tests and operator introspection.
func (s *Server) HubFederationRegistrySnapshot() *federation.FederationRegistry {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := federation.NewRegistry()
	out.SchemaVersion = s.hub.registry.SchemaVersion
	out.Spokes = append(out.Spokes, s.hub.registry.Spokes...)
	return out
}

// HubFederationWarnings returns plain-HTTP-accepted-registration WARN messages
// captured since the server started. Test-only helper.
func (s *Server) HubFederationWarnings() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.warnings...)
}

// HubFederationConflicts returns 409 conflict log messages captured since the
// server started. Test-only helper.
func (s *Server) HubFederationConflicts() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.conflictsLog...)
}

// requireFederationTrusted enforces the federation-specific peer policy:
// loopback / ts-net peers are always accepted; non-trusted peers are accepted
// only when --federation-allow-plain-http is set. Distinct from
// requireTrusted so the AC-strict default doesn't depend on a global flag.
func (s *Server) requireFederationTrusted(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if isTrusted(r) {
			next(w, r)
			return
		}
		if s.hub != nil && s.hub.allowPlainHTTP {
			next(w, r)
			return
		}
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: ts-net or loopback peer required for /api/federation/* (use --federation-allow-plain-http to opt out)"})
	}
}

// federationRegisterRequest is the spokeŌåÆhub registration / re-registration
// payload. Identity = (NodeID, IdentityFingerprint). NodeID is the stable
// federation key; IdentityFingerprint distinguishes a re-registration of the
// same node from a duplicate-name conflict (different machine claiming an
// already-registered node_id).
type federationRegisterRequest struct {
	NodeID               string   `json:"node_id"`
	IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
	Name                 string   `json:"name"`
	URL                  string   `json:"url"`
	DDxVersion           string   `json:"ddx_version"`
	SchemaVersion        string   `json:"schema_version"`
	GraphQLSchemaVersion string   `json:"graphql_schema_version,omitempty"`
	Capabilities         []string `json:"capabilities,omitempty"`
	ProjectIDs           []string `json:"project_ids,omitempty"`
}

// federationRegisterResponse is sent on a successful (200/201) registration.
type federationRegisterResponse struct {
	NodeID string                 `json:"node_id"`
	Status federation.SpokeStatus `json:"status"`
	Reason string                 `json:"reason"`
	Spoke  federation.SpokeRecord `json:"spoke"`
}

// identityFingerprintKey is the SpokeRecord.Capabilities-adjacent slot we
// stash the fingerprint in. To keep the on-disk schema stable (B14.2 froze
// SpokeRecord shape), we encode it as a synthetic capability prefixed with
// "@identity:". Future schema versions can hoist it to a first-class field.
const identityFingerprintPrefix = "@identity:"

func setIdentityFingerprint(rec *federation.SpokeRecord, fp string) {
	cleaned := rec.Capabilities[:0]
	for _, c := range rec.Capabilities {
		if !strings.HasPrefix(c, identityFingerprintPrefix) {
			cleaned = append(cleaned, c)
		}
	}
	rec.Capabilities = cleaned
	if fp != "" {
		rec.Capabilities = append(rec.Capabilities, identityFingerprintPrefix+fp)
	}
}

func getIdentityFingerprint(rec federation.SpokeRecord) string {
	for _, c := range rec.Capabilities {
		if strings.HasPrefix(c, identityFingerprintPrefix) {
			return strings.TrimPrefix(c, identityFingerprintPrefix)
		}
	}
	return ""
}

func (s *Server) handleFederationRegister(w http.ResponseWriter, r *http.Request) {
	var req federationRegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}
	if strings.TrimSpace(req.URL) == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "url required"})
		return
	}

	hs := federation.Handshake(s.hub.hubDDxVersion, s.hub.hubSchemaVer, req.DDxVersion, req.SchemaVersion)
	if !hs.Accept {
		writeJSON(w, http.StatusBadRequest, map[string]string{
			"error":  "version handshake failed",
			"reason": hs.Reason,
		})
		return
	}

	now := s.hub.now().UTC()

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	if existing := s.hub.registry.FindSpoke(req.NodeID); existing != nil {
		existingFP := getIdentityFingerprint(*existing)
		// Identity conflict: a different machine claims an already-registered
		// node_id. Reject with 409 and log.
		if existingFP != "" && req.IdentityFingerprint != "" && existingFP != req.IdentityFingerprint {
			msg := fmt.Sprintf("federation: duplicate node_id %q from different identity (existing=%s, attempted=%s)",
				req.NodeID, existingFP, req.IdentityFingerprint)
			s.hub.conflictsLog = append(s.hub.conflictsLog, msg)
			s.hub.warnLog("%s", msg)
			writeJSON(w, http.StatusConflict, map[string]string{
				"error":  "node_id already registered to a different identity",
				"reason": "duplicate_node_id",
			})
			return
		}
	}

	rec := federation.SpokeRecord{
		NodeID:        req.NodeID,
		Name:          req.Name,
		URL:           req.URL,
		DDxVersion:    req.DDxVersion,
		SchemaVersion: req.SchemaVersion,
		Capabilities:  append([]string(nil), req.Capabilities...),
		ProjectIDs:    append([]string(nil), req.ProjectIDs...),
		RegisteredAt:  now,
		LastHeartbeat: time.Time{},
		Status:        hs.Status,
	}
	setIdentityFingerprint(&rec, req.IdentityFingerprint)
	if err := s.hub.registry.UpsertSpoke(rec); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
		return
	}
	s.persistFederationLocked()

	// Emit WARN if this registration was accepted via the plain-HTTP opt-out.
	if s.hub.allowPlainHTTP && !isTrusted(r) {
		msg := fmt.Sprintf("federation: accepted plain-HTTP registration node_id=%q url=%q from remote=%s",
			req.NodeID, req.URL, r.RemoteAddr)

package server

import (
	"context"
	"fmt"
	"log"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// federationSpoke holds the per-server state for spoke-mode federation: the
// running spoke lifecycle agent and its config (so tests can introspect what
// was advertised to the hub).
type federationSpoke struct {
	agent   *federation.Spoke
	hubURL  string
	selfURL string
}

// EnableSpokeMode launches the spoke-side lifecycle: register-on-start,
// jittered heartbeat, URL-change detection across restarts, and best-effort
// deregister-on-shutdown. Idempotent: a second call is a no-op.
//
// hubURL is the federation hub base URL (e.g. "https://hub:7743").
// selfURL is this server's externally-reachable URL advertised to the hub
// (e.g. "https://node-a:7743"). When empty, a default is constructed from
// the bind address.
//
// The returned error reflects the initial registration outcome ŌĆö if the hub
// rejects the registration (version mismatch, identity conflict, etc.) the
// spoke does not start.
//
// Both EnableHubMode and EnableSpokeMode may be called on the same server
// (hub_spoke role).
func (s *Server) EnableSpokeMode(ctx context.Context, hubURL, selfURL string, opts ...SpokeOption) error {
	if s.spoke != nil {
		return nil
	}
	if strings.TrimSpace(hubURL) == "" {
		return fmt.Errorf("federation: --hub-address URL required for spoke mode")
	}
	if strings.TrimSpace(selfURL) == "" {
		// Best-effort default: scheme is https + bind address. Operators can
		// override via the explicit selfURL arg.
		selfURL = "https://" + s.Addr
	}

	cfg := federation.SpokeConfig{
		NodeID:        s.state.Node.ID,
		Name:          s.state.Node.Name,
		URL:           selfURL,
		HubURL:        hubURL,
		DDxVersion:    HubDefaultDDxVersion,
		SchemaVersion: federation.CurrentSchemaVersion,
		Logger:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
	}
	for _, proj := range s.state.GetProjects() {
		if proj.ID != "" {
			cfg.ProjectIDs = append(cfg.ProjectIDs, proj.ID)
		}
	}
	for _, opt := range opts {
		opt(&cfg)
	}

	agent, err := federation.NewSpoke(cfg)
	if err != nil {
		return err
	}

	if agent.URLChanged() {
		log.Printf("federation: spoke URL changed from %q to %q; will re-register with new URL",
			agent.PreviousURL(), selfURL)
	}

	if err := agent.Start(ctx); err != nil {
		return fmt.Errorf("federation: spoke register: %w", err)
	}

	s.spoke = &federationSpoke{agent: agent, hubURL: hubURL, selfURL: selfURL}
	s.SpokeMode = true
	return nil
}

// SpokeOption customises the SpokeConfig used by EnableSpokeMode.
type SpokeOption func(*federation.SpokeConfig)

// SpokeAgent exposes the underlying federation.Spoke for tests and operator
// introspection. Returns nil if spoke mode is not enabled.
func (s *Server) SpokeAgent() *federation.Spoke {
	if s.spoke == nil {
		return nil
	}
	return s.spoke.agent
}

// ShutdownSpoke stops the spoke lifecycle (heartbeat + best-effort deregister).
// Safe to call when spoke mode is not enabled ŌĆö returns nil. Called from
// graceful shutdown paths so the hub registry does not show a stale spoke.
func (s *Server) ShutdownSpoke(ctx context.Context) error {
	if s.spoke == nil {
		return nil
	}
	return s.spoke.agent.Shutdown(ctx)
}

// RegisterProject adds (or refreshes) a project entry on the server's state
// and persists the updated state file. Returns the stored entry.
func (s *Server) RegisterProject(path string) ProjectEntry {
	entry := s.state.RegisterProject(path)
	_ = s.state.save()
	return entry
}

// Shutdown stops the server's background services: closes the bead lifecycle
// hub and stops all land coordinators. Returns the first error encountered.
// Both operations are idempotent and safe to call on an idle server.
func (s *Server) Shutdown() error {
	// Best-effort spoke deregister so the hub registry does not show this
	// node as stale after a graceful shutdown. Errors are swallowed inside
	// ShutdownSpoke (the hub may legitimately be down).
	if s.spoke != nil {
		ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
		_ = s.ShutdownSpoke(ctx)
		cancel()
	}
	s.beadHub.Close()
	s.workers.LandCoordinators.StopAll()
	return nil
}

// ListenAndServe starts the server. If TsnetConfig.Enabled is true, a parallel
// Tailscale ts-net listener is started alongside the standard localhost listener.
func (s *Server) ListenAndServe() error {
	release, err := acquireSingletonLock()
	if err != nil {
		return err
	}
	defer release()
	s.installSingletonReleaseOnSignal(release)
	s.writeAddrFile("http")
	if s.TsnetConfig != nil && s.TsnetConfig.Enabled {
		errCh := make(chan error, 2)

		// Standard localhost listener
		go func() {
			errCh <- http.ListenAndServe(s.Addr, s.mux)
		}()

		// ts-net listener
		go func() {
			errCh <- s.listenTsnet()
		}()

		return <-errCh
	}
	return http.ListenAndServe(s.Addr, s.mux)
}

// ListenAndServeTLS starts the server with TLS. If certFile and keyFile are
// empty, a self-signed certificate is auto-generated and cached under
// workingDir/.ddx/server/tls/.
func (s *Server) ListenAndServeTLS(certFile, keyFile string) error {
	release, err := acquireSingletonLock()
	if err != nil {
		return err
	}
	defer release()
	s.installSingletonReleaseOnSignal(release)
	if certFile == "" || keyFile == "" {
		var err error
		tlsDir := filepath.Join(s.WorkingDir, ".ddx", "server", "tls")
		certFile, keyFile, err = ensureSelfSignedCert(tlsDir)
		if err != nil {
			return fmt.Errorf("generating self-signed cert: %w", err)
		}
	}
	s.writeAddrFile("https")
	if s.TsnetConfig != nil && s.TsnetConfig.Enabled {
		errCh := make(chan error, 2)
		go func() {
			errCh <- http.ListenAndServeTLS(s.Addr, certFile, keyFile, s.mux)
		}()
		go func() {
			errCh <- s.listenTsnet()
		}()
		return <-errCh
	}
	return http.ListenAndServeTLS(s.Addr, certFile, keyFile, s.mux)
}

// writeAddrFile writes the server's address to a user-level file so CLI
// clients can auto-discover it without configuration.
func (s *Server) writeAddrFile(scheme string) {
	type addrFile struct {
		Node      string    `json:"node"`
		NodeID    string    `json:"node_id"`
		URL       string    `json:"url"`
		PID       int       `json:"pid"`
		StartedAt time.Time `json:"started_at"`
	}
	af := addrFile{
		Node:      s.state.Node.Name,
		NodeID:    s.state.Node.ID,
		URL:       fmt.Sprintf("%s://%s", scheme, s.Addr),
		PID:       os.Getpid(),
		StartedAt: s.startTime,
	}
	data, err := json.MarshalIndent(af, "", "  ")
	if err != nil {
		return
	}
	dir := serverAddrDir()
	if err := os.MkdirAll(dir, 0700); err != nil {
		return
	}
	_ = os.WriteFile(filepath.Join(dir, "server.addr"), data, 0600)
}

// serverAddrDir returns the user-level directory for the server address file.
// Follows XDG_DATA_HOME if set, else ~/.local/share/ddx.
func serverAddrDir() string {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx")
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join("/tmp", "ddx")
	}
	return filepath.Join(home, ".local", "share", "ddx")
}

// ReadServerAddr reads the last-written server address from the user-level
// addr file. Returns "" if none is present, or if the recorded pid is not
// alive (in which case a warning is emitted and the stale file is best-effort
// cleared so callers fall back to the default URL).
func ReadServerAddr() string {
	type addrFile struct {
		URL string `json:"url"`
		PID int    `json:"pid"`
	}
	path := filepath.Join(serverAddrDir(), "server.addr")
	data, err := os.ReadFile(path)
	if err != nil {
		return ""
	}
	var af addrFile
	if err := json.Unmarshal(data, &af); err != nil {
		return ""
	}
	if af.PID > 0 && !processAlive(af.PID) {
		fmt.Fprintf(addrFallbackWarnWriter,
			"warning: server.addr points to a dead pid %d; falling back to default 127.0.0.1:7743\n",
			af.PID)
		_ = os.Remove(path)
		return ""
	}
	return af.URL
}

// installSingletonReleaseOnSignal arranges for the singleton lock to be
// released on SIGTERM/SIGINT so that the next ddx-server can start without
// having to wait for stale-lock detection. The handler exits the process
// with a conventional non-zero status; defers in ListenAndServe(TLS) do not
// run, but the lock release fires explicitly here.
func (s *Server) installSingletonReleaseOnSignal(release func()) {
	ch := make(chan os.Signal, 1)
	signal.Notify(ch, os.Interrupt, syscall.SIGTERM)
	go func() {
		<-ch
		release()
		os.Exit(130)
	}()
}

// ensureSelfSignedCert returns paths to a self-signed cert/key in dir,
// generating them if they don't already exist.
func ensureSelfSignedCert(dir string) (certFile, keyFile string, err error) {
	if err = os.MkdirAll(dir, 0700); err != nil {
		return
	}
	certFile = filepath.Join(dir, "cert.pem")
	keyFile = filepath.Join(dir, "key.pem")

	// Re-use existing pair if both files are present and cert is still valid.
	if _, e1 := os.Stat(certFile); e1 == nil {
		if _, e2 := os.Stat(keyFile); e2 == nil {
			if pair, e3 := tls.LoadX509KeyPair(certFile, keyFile); e3 == nil {
				leaf, e4 := x509.ParseCertificate(pair.Certificate[0])
				if e4 == nil && time.Now().Before(leaf.NotAfter.Add(-24*time.Hour)) {
					return certFile, keyFile, nil
				}
			}
		}
	}

	// Generate new key + cert.
	key, e := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
	if e != nil {
		err = e
		return
	}
	serial, _ := rand.Int(rand.Reader, new(big.Int).Lsh(big.NewInt(1), 128))
	tmpl := &x509.Certificate{
		SerialNumber: serial,
		Subject:      pkix.Name{CommonName: "ddx-server"},
		NotBefore:    time.Now().Add(-time.Minute),
		NotAfter:     time.Now().Add(10 * 365 * 24 * time.Hour),
		KeyUsage:     x509.KeyUsageKeyEncipherment | x509.KeyUsageDigitalSignature,
		ExtKeyUsage:  []x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},
		IPAddresses:  []net.IP{net.ParseIP("127.0.0.1"), net.ParseIP("0.0.0.0")},
		DNSNames:     []string{"localhost"},
	}
	certDER, e := x509.CreateCertificate(rand.Reader, tmpl, tmpl, &key.PublicKey, key)
	if e != nil {
		err = e
		return
	}

	cf, e := os.OpenFile(certFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if e != nil {
		err = e
		return
	}
	_ = pem.Encode(cf, &pem.Block{Type: "CERTIFICATE", Bytes: certDER})
	_ = cf.Close()

	kf, e := os.OpenFile(keyFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if e != nil {
		err = e
		return
	}
	keyDER, _ := x509.MarshalECPrivateKey(key)
	_ = pem.Encode(kf, &pem.Block{Type: "EC PRIVATE KEY", Bytes: keyDER})
	_ = kf.Close()

	return certFile, keyFile, nil
}

// listenTsnet starts a Tailscale ts-net TLS listener and serves the same mux.
func (s *Server) listenTsnet() error {
	tc := s.TsnetConfig
	hostname := tc.Hostname
	if hostname == "" {
		hostname = "ddx"
	}
	stateDir := tc.StateDir
	if stateDir == "" {
		stateDir = filepath.Join(s.WorkingDir, ".ddx", "tsnet")
	}

	ts := &tsnet.Server{
		Hostname: hostname,
		Dir:      stateDir,
		AuthKey:  tc.AuthKey,
	}
	defer func() { _ = ts.Close() }()

	ln, err := ts.ListenTLS("tcp", ":443")
	if err != nil {
		return fmt.Errorf("tsnet listen: %w", err)
	}
	defer func() { _ = ln.Close() }()

	fmt.Printf("DDx ts-net listener active: https://%s\n", hostname)
	return http.Serve(ln, tsnetMiddleware(ts, s.mux))

