		Errors:        map[string]error{},
		Skipped:       map[string]SkipReason{},
		StatusUpdates: map[string]SpokeStatus{},
		Nodes:         results,
	}
	for _, r := range results {
		switch r.Outcome {
		case OutcomeOK:
			out.Responses[r.NodeID] = r.Response
		case OutcomeSkipped:
			out.Skipped[r.NodeID] = r.SkipReason
		default:
			if r.Err != nil {
