	if got := gotHeaders.Get("X-DDx-Coordinator-Identity"); got != "coord-456" {
		t.Fatalf("coordinator header = %q, want %q", got, "coord-456")
	}
	if string(gotBody) != `{"query":"mutation { doThing }"}` {
		t.Fatalf("spoke body = %s", string(gotBody))
	}
